var tractorsDataDefault = []byte(`[{"id":"1770900139736","name":"Трактор BELARUS-422","images":[],"brand":"BELARUS","color":"Синий","engineType":"gasoline","horsepower":280,"year":2018,"mileage":4700,"vin":"56SF546GFG6465456","pts":"21465165454654","ptsOwners":5,"location":"Ленинградская область, г. Гатчина","phone":"+79995147654","ownerName":"Александр Петров","description":"Мужики, этот BELARUS-422 — просто зверюга! Шесть лет на нём пахал в прямом смысле слова, и каждое утро заводил с улыбкой. 280 лошадей под капотом — это не шутки, тянет всё что угодно и даже не пыхтит. Помню, как в первый раз сел за руль — аж мурашки по коже! Синий красавец, соседи до сих пор оборачиваются. Движок бензиновый, кто понимает — тот оценит, работает мягко и ровно. За 4700 моточасов ни разу не подвёл, хоть в дождь, хоть в мороз. Продаю земельный участок, а без земли зачем мне трактор? Эх, если б можно было его в квартиру забрать...","price":1000000},{"id":"698dcec45c3dcc9682b2eaef","name":"Беларус МТЗ-82","images":[],"brand":"МТЗ","color":"Синий","engineType":"gasoline","horsepower":80,"year":2018,"mileage":3200,"vin":"XTA82181JR0123456","pts":"77345612348912","ptsOwners":1,"location":"Москва, Россия","phone":"+79161234567","ownerName":"Иван Смирнов","description":"Знаете, я купил этого МТЗ-82 новым в 2018-м и с тех пор он стал буквально членом семьи. Жена смеётся, говорит, что я его чаще мою, чем машину. А что? Он того стоит! 80 сил — казалось бы, немного, но этот парень умудряется делать работу за двоих. Синий цвет — просто загляденье на фоне зелёного поля. Я единственный владелец, берёг как зеницу ока: тёплый гараж, замена масла строго по регламенту, все фильтры вовремя. 3200 моточасов — и он урчит как новый. ПТС чистый, один хозяин. Обстоятельства заставляют расстаться, но я хочу, чтобы он попал в хорошие руки.","price":850000},{"id":"698dcec55c3dcc9682b2eaf0","name":"John Deere 6120","images":[],"brand":"John Deere","color":"Зеленый","engineType":"diesel","horsepower":120,"year":2020,"mileage":1500,"vin":"1JDJD6120LR045678","pts":"56218934712312","ptsOwners":1,"location":"Краснодар, Россия","phone":"+79161234568","ownerName":"Дмитрий Краснов","description":"Всю жизнь мечтал о John Deere — и вот в 2020-м наконец осуществил мечту! Когда этот зелёный красавец впервые заехал на моё поле, я чуть не прослезился, честное слово. 120 лошадок дизеля — золотая середина: и мощи хватает, и солярку не жрёт как не в себя. Кабина — как космический корабль, сидишь и кайфуешь. За полтора тысячи моточасов я к нему так привязался, что дочка ревнует. Каждую весну выезжаю на поле первым в районе — и каждый раз горжусь этим трактором. Обслуживал только у официалов, всё по книжке. Один хозяин, ПТС оригинал.","price":2300000},{"id":"698dcec65c3dcc9682b2eaf1","name":"Кировец К-700А","images":[],"brand":"Кировец","color":"Желтый","engineType":"diesel","horsepower":235,"year":2015,"mileage":8900,"vin":"XTK700A15JR098765","pts":"34126789452325","ptsOwners":2,"location":"Ростов-на-Дону, Россия","phone":"+79161234569","ownerName":"Сергей Волков","description":"Кировец К-700А — это не трактор, это ТАНК! Жёлтый гигант, 235 лошадей, и когда он рычит — земля дрожит в радиусе километра. Я второй владелец, взял у деда-фермера, который на нём 30 лет отработал и на пенсию ушёл. Деду спасибо — машина в идеале. Кировец — это вообще отдельная философия: садишься за штурвал и чувствуешь себя капитаном корабля. 8900 моточасов для К-700 — это юность, они по 50 тысяч ходят без капиталки! Масло менял каждые 250 часов, фильтры — как положено. Я на нём и пахал, и снег зимой чистил, и соседу дом из брёвен перетащил. Легенда, а не трактор.","price":1750000},{"id":"698dcec65c3dcc9682b2eaf2","name":"Т-150К","images":["assets/images/tractors/69a58b428880a47039011744.webp"],"brand":"ХТЗ","color":"Красный","engineType":"diesel","horsepower":165,"year":2012,"mileage":12000,"vin":"XTT150K12JR234567","pts":"89234561237878","ptsOwners":3,"location":"Волгоград, Россия","phone":"+79161234570","ownerName":"Николай Орлов","description":"Т-150К — мой красный воин! Купил его в 2012 году и с тех пор мы с ним неразлучны. Знаете, что мне в нём нравится больше всего? Простота и надёжность. Никакой электроники, никаких заморочек — сел и поехал. 165 дизельных лошадей тянут так, что любой импортник позавидует. 12 000 моточасов — а он как новенький, потому что руки у меня растут откуда надо и я за ним слежу. Красный цвет на поле — это что-то! Издалека видно, все знают — это мой Т-150 едет. Три владельца по ПТС, но последние 10 лет — только я. Перехожу на более мощную технику, а этот боец заслуживает хозяина, который будет его ценить.","price":950000},{"id":"698dcec75c3dcc9682b2eaf3","name":"Fendt 936 Vario","images":[],"brand":"Fendt","color":"Зеленый","engineType":"diesel","horsepower":360,"year":2021,"mileage":800,"vin":"WF0936VA2LR123456","pts":"12345678901254","ptsOwners":1,"location":"Санкт-Петербург, Россия","phone":"+79161234571","ownerName":"Михаил Лебедев","description":"Fendt 936 Vario — это Мерседес среди тракторов, и я говорю это без преувеличения. Когда я впервые попал в эту кабину — подумал, что случайно сел в бизнес-джет. Климат-контроль, мультимедиа, автопилот... А под капотом 360 лошадей, которые работают так тихо, что можно музыку слушать на минимальной громкости. Вариатор — отдельная песня, переключения передач просто не существует, плавность хода невероятная. Купил в 2021-м, наработка всего 800 часов — практически новый. Я каждый раз, садясь в него, чувствую себя как ребёнок в парке аттракционов. Немецкое качество в каждой детали. Один владелец, полная сервисная история.","price":5200000},{"id":"698dcec85c3dcc9682b2eaf4","name":"Case IH Magnum 340","images":[],"brand":"Case IH","color":"Красный","engineType":"diesel","horsepower":340,"year":2019,"mileage":2400,"vin":"4RB340MG1KR456789","pts":"45678901234545","ptsOwners":1,"location":"Самара, Россия","phone":"+79161234572","ownerName":"Андрей Новиков","description":"Case IH Magnum 340 — для меня это как первая любовь, только лучше, потому что не подводит! Красный дьявол с 340 лошадьми — когда он выходит на поле, у соседей челюсти отвисают. Купил в 2019-м и с тех пор каждый сезон — чистый восторг. Знаете что самое крутое? Он одинаково хорош и на пахоте, и на севе, и на транспортных работах. Универсал! Подвеска кабины — отдельный кайф, после 12 часов за рулём спина не болит. За 2400 моточасов — ни одного серьёзного ремонта, только плановое ТО. Я фермер в третьем поколении и повидал много техники, но этот Case — лучшее, на чём я работал.","price":4800000},{"id":"698dcec95c3dcc9682b2eaf5","name":"Беларус МТЗ-1221","images":[],"brand":"МТЗ","color":"Оранжевый","engineType":"diesel","horsepower":130,"year":2017,"mileage":4500,"vin":"XTA1221J7R0987654","pts":"78901234567865","ptsOwners":1,"location":"Казань, Россия","phone":"+79161234573","ownerName":"Рустам Галиев","description":"МТЗ-1221 — мой оранжевый апельсин! Когда покупал в 2017-м, жена крутила у виска — мол, зачем тебе трактор, у нас 10 соток. А теперь у нас 50 гектаров и она сама просит покататься! 130 лошадей дизеля — идеальный баланс мощности и экономичности. Этот трактор научил меня любить землю по-настоящему. Каждое утро я выхожу в поле, завожу его — и мотор поёт, как хор мальчиков. 4500 моточасов, всё родное, ничего не менялось кроме расходников. Я единственный хозяин, и я точно знаю историю каждой царапинки на нём. Обслуживал строго по регламенту, держал в отапливаемом ангаре.","price":1200000},{"id":"698dcec95c3dcc9682b2eaf6","name":"New Holland T7.270","images":[],"brand":"New Holland","color":"Синий","engineType":"diesel","horsepower":270,"year":2020,"mileage":1800,"vin":"ZEAMT7270LR234567","pts":"23456789012356","ptsOwners":1,"location":"Воронеж, Россия","phone":"+79161234574","ownerName":"Виктор Зайцев","description":"New Holland T7.270 — мой синий великан, моя гордость и радость! Я выбирал между ним и конкурентами полгода, объездил все выставки, перечитал все форумы — и ни секунды не жалею о выборе. 270 лошадей работают настолько слаженно, что кажется, будто трактор читает твои мысли. Купил в 2020-м, и с тех пор каждый выезд в поле — как праздник. Расход топлива приятно удивляет, для такой мощности — просто копейки. 1800 моточасов, состояние близкое к идеальному. Соседи приходят просто посмотреть на него, а один даже фотографировался рядом для соцсетей! Все документы в порядке, ПТС чистый, один владелец.","price":3900000},{"id":"698dceca5c3dcc9682b2eaf7","name":"Massey Ferguson 8737","images":[],"brand":"Massey Ferguson","color":"Красный","engineType":"diesel","horsepower":370,"year":2022,"mileage":500,"vin":"AGCMF8737NR345678","pts":"56789012345678","ptsOwners":1,"location":"Новосибирск, Россия","phone":"+79161234575","ownerName":"Павел Морозов","description":"Massey Ferguson 8737 — это моя мечта, которая стала реальностью в 2022 году! 370 лошадей в красном корпусе — когда он заводится, у меня до сих пор мурашки по коже бегут. Всего 500 моточасов — считай, только обкатку прошёл. Этот трактор — произведение инженерного искусства: каждая кнопка на своём месте, каждый рычаг отзывается моментально. Я вёл дневник работы на нём — ни единой поломки, ни единого сбоя. Масло менял досрочно, фильтры — только оригинал, хранил в тёплом ангаре с системой вентиляции. Сын говорит, что я люблю этот трактор больше, чем его — ну, может, он немного прав! Один владелец, ПТС оригинал.","price":6100000},{"id":"698dcecb5c3dcc9682b2eaf8","name":"ДТ-75М","images":[],"brand":"Волгоградский тракторный завод","color":"Зеленый","engineType":"diesel","horsepower":95,"year":2010,"mileage":15000,"vin":"XTDT75M10JR567890","pts":"89012345678948","ptsOwners":4,"location":"Омск, Россия","phone":"+79161234576","ownerName":"Геннадий Титов","description":"ДТ-75М — легенда советского тракторостроения, и мой личный герой! Этот зелёный гусеничный боец прошёл 15 000 моточасов и хоть бы хны. Знаете, что в нём прекрасно? Его можно починить в поле с помощью кувалды и какой-то матери — и он поедет дальше! 95 дизельных лошадей, простых и честных, без всяких турбин и электроники. Я на нём и целину поднимал, и болота месил — прёт как лось и ничего не боится. Четыре владельца по ПТС, но каждый любил его как родного. У меня он с 2015 года, и я знаю в нём каждый болтик. Когда утром заводишь этот дизель и он начинает тарахтеть — это лучшая музыка на свете!","price":650000},{"id":"698dcecc5c3dcc9682b2eaf9","name":"Валтра N174","images":[],"brand":"Valtra","color":"Красный","engineType":"diesel","horsepower":174,"year":2019,"mileage":3100,"vin":"VALTN174JR0678901","pts":"12345678901223","ptsOwners":1,"location":"Екатеринбург, Россия","phone":"+79161234577","ownerName":"Алексей Бурков","description":"Валтра N174 — финское качество, которое чувствуешь каждой клеточкой тела! Я агроном по образованию и за 20 лет работы перепробовал кучу техники, но Valtra — это отдельная вселенная. 174 л.с. дизеля работают так тихо и плавно, что я первое время думал, что двигатель не завёлся. Красный цвет — нетипичный для Валтры, и именно поэтому мой трактор уникален. Кабина — лучшая эргономика, что я встречал: после 10-часовой смены чувствуешь себя отдохнувшим. 3100 моточасов, обслуживание строго у дилера, все чеки сохранены. Один хозяин. Финны знают толк в тракторах, поверьте старому агроному!","price":2800000}]`)

